def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[idx] = np.inf
            continue
        base_score = 0
        scale = 1.0
        decay = 1.0
        complexity = 1.0
        enhance = 1.0
        for m in range(1, 16):
            if m % 2 == 0 and m % 3 == 0:
                scale *= 1.07 + 0.015 * m
            elif m % 4 == 0:
                scale *= 0.92 - 0.008 * m
            if ratio < 0.08 * m:
                base_score += (m ** 3) / (1 + np.exp(-ratio * m)) * scale
            else:
                base_score += (np.log1p(m * m * m) + np.sqrt(ratio) * m) * scale / (m + 1)
            if (cap + m * 2) % 9 == 0:
                base_score *= 1.06
            elif (cap * m) % 11 == 0:
                base_score *= 0.93
            if m == 8:
                sub_penalty = 0
                for n in range(1, 7):
                    delta = cap - item * (n ** 3)
                    if delta > 0:
                        if delta % (n + 3) == 0:
                            sub_penalty += np.cbrt(delta) / (n + 4)
                        else:
                            sub_penalty -= np.log1p(abs(delta)) / (n + 3)
                    else:
                        sub_penalty -= abs(delta) ** 1.7 / (n + 6)
                base_score += sub_penalty * 0.9
            if ratio > 0.9 and m % 3 == 0:
                complexity *= 1.12 + 0.025 * m
            elif ratio < 0.15 and m % 4 == 1:
                complexity *= 0.85 - 0.012 * m
            if (cap + m) % 5 == 0 and ratio > 0.5:
                enhance *= 1.03
            if m % 5 == 2 and cap % (m + 2) == 0:
                decay -= np.cos(m * ratio) * 0.4
            if base_score < 0:
                base_score = abs(base_score) * 0.75
            else:
                base_score *= decay
        base_score *= complexity * enhance
        if ratio < 0.1:
            score = -base_score * (np.log1p(cap * 2 + item) + np.sqrt(cap)) * 0.85
        elif cap > item * 5:
            score = -base_score / (np.sqrt(cap) + 2) * (1 + ratio) * 1.1
        else:
            score = -base_score / (cap + 5) * np.exp(-ratio ** 1.5) * 0.95
        if ratio > 0.97:
            score *= 1.2
        elif ratio < 0.03:
            score *= 0.65
        if cap % 3 == 0:
            score *= 0.96
        elif cap % 7 == 0:
            score *= 1.04
        adjust_factor = 1.0
        for p in range(1, 4):
            if (cap + p * item) % 4 == 0:
                adjust_factor *= 1.01 * p
            else:
                adjust_factor *= 0.99 / (p + 1)
            if ratio > 0.7 + 0.05 * p:
                adjust_factor *= 1.02
        priorities[idx] = score * adjust_factor
    return priorities
